    # Test 6: gate_drift_report returns correct structure
    _current6 = {"gate_01": 10.0, "gate_02": 5.0}
    _baseline6 = {"gate_01": 8.0, "gate_02": 5.0}
    _report6 = _gdr(_current6, _baseline6)
