    _g11b_result = _g11_analytics_check("Edit", {"file_path": "/tmp/test.py"}, _g11b_state)
    test("Gate 11: normal tool still appends timestamp",
         len(_g11b_state.get("rate_window_timestamps", [])) == 1)

