    _gtr_orig_trend_path = _gtr_mod._trend_path
    _gtr_tmp = _gtr_tempfile.NamedTemporaryFile(suffix=".json", delete=False)
    _gtr_tmp.close()
    _gtr_tmp_path = _gtr_tmp.name
