        _t2 = f"2025-01-15T10:{30 + _i}:01"
        _chain_entries.append({"gate": "GA", "tool": "Edit", "session_id": "s1", "timestamp": _t1, "decision": "pass"})
        _chain_entries.append({"gate": "GB", "tool": "Edit", "session_id": "s1", "timestamp": _t2, "decision": "pass"})
