    test("HR: get_mtime existing file", _get_mtime(__file__) is not None)
    test("HR: get_mtime nonexistent", _get_mtime("/nonexistent/path.py") is None)

    # ── _validate_module ──
    _hr_good_mod = _hr_types.ModuleType("test_good")
